                    { "id": "b", "text": "b. Gain from revaluation of building" },
                    { "id": "c", "text": "c. Revaluation surplus" },
                    { "id": "d", "text": "d. Revaluation revenue." },
                    { "id": "e", "text": "e. Accumulated Depreciation." }
